import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"王气","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/王气.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/王气.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/王气.md"};function l(i,a,p,_,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"王气",tabindex:"-1"},[s("王气 "),e("a",{class:"header-anchor",href:"#王气","aria-label":'Permalink to "王气"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序008")])])],-1),o('<h1 id="王气-1" tabindex="-1">王气 <a class="header-anchor" href="#王气-1" aria-label="Permalink to &quot;王气&quot;">​</a></h1><p>王气<br> 10XP<br> 特异本质<br> 这是一缕代表运势与造化之气，是象征帝王运数的祥瑞之气。获得王气只能使用经验进行购买，在购买后，王气将存在于购买者的体内。<br> 在中国古代世界影片中，购买者会被认为有帝王之相，或有惊为天人的气质。<br> 当购买者被近战攻击时，若其不着甲或已着轻甲，且被攻击时，购买者并未进行过格挡，则一缕淡淡的气会从其身体中飘出，为购买者护体，此时王气会为购买者提供3点临时生命，这些临时生命在一场战斗中若被击毁，则不会再恢复直至这场战斗结束。在这场战斗结束后，王气将会缓慢恢复它带来的临时生命，以每20分钟恢复1点的速度自动恢复，同时，在对抗擒抱检定时，王气此时每剩余1点未被击毁的临时生命，就会额外提供1点对抗擒抱检定上的力量加值。</p><p>选开：所有与拥有王气者战斗的敌人都会隐约的感觉到有这股气的存在，他们可以以一个战斗中侦查动作通过一个智力-学识-专业：玄学检定，对抗其风度-隐秘-专业：掩饰，若对抗成功，则会有画外音（或场景内某人）念出“王浚楼船下益州，金陵王气黯然收。”<br> 同时，在此场景内，王气立即失效。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
